import json
import re

# Load UNIV CALIFORNIA patents
with open(var_functions.query_db:64, 'r') as f:
    univ_patents = json.load(f)

univ_cpc_mapping = {}
for patent in univ_patents:
    patents_info = patent['Patents_info']

    pub_num = None
    # Try different patterns for extracting publication number
    patterns = [
        r'pub\. number\s+([A-Z]{2}-[^\s,\.]+)',
        r'publication number\s+([A-Z]{2}-[^\s,\.]+)',
        r'publication no\.\s+([A-Z]{2}-[^\s,\.]+)'
    ]

    for pat in patterns:
        match = re.search(pat, patents_info, re.IGNORECASE)
        if match:
            pub_num = match.group(1).strip()
            break

    if pub_num:
        primary_cpc = []
        if patent['cpc'] and patent['cpc'] != '[]':
            try:
                cpc_data = json.loads(patent['cpc'])
                primary_cpc = [item['code'] for item in cpc_data if item.get('first', False)]
            except:
                pass
        univ_cpc_mapping[pub_num] = primary_cpc

result = {
    'total_univ_patents': len(univ_cpc_mapping),
    'sample': dict(list(univ_cpc_mapping.items())[:5])
}

print('__RESULT__:')
print(json.dumps(result))

