import json

# Load UNIV CALIFORNIA data and CPC definitions
with open(var_functions.query_db:64, 'r') as f:
    univ_data = json.load(f)

with open(var_functions.query_db:62, 'r') as f:
    cpc_defs = json.load(f)

# Create CPC title mapping
cpc_title_map = {item['symbol']: item['titleFull'] for item in cpc_defs}

# Process UNIV CALIFORNIA patents
univ_cpc = {}
for patent in univ_data:
    info = patent['Patents_info']

    # Simple publication number extraction (first occurrence of Country-Number pattern)
    if 'US-' in info:
        start = info.find('US-')
        end = info.find(' ', start)
        if end == -1:
            end = len(info)
        pub_num = info[start:end]
    elif 'TW-' in info:
        start = info.find('TW-')
        end = info.find(' ', start)
        if end == -1:
            end = len(info)
        pub_num = info[start:end]
    else:
        continue

    # Get primary CPC codes
    primary_cpc = []
    if patent['cpc'] and patent['cpc'] != '[]':
        try:
            cpc_list = json.loads(patent['cpc'])
            primary_cpc = [item['code'] for item in cpc_list if item.get('first', False)]
        except:
            pass

    if pub_num:
        univ_cpc[pub_num] = primary_cpc

result = {
    'total_univ_patents': len(univ_cpc),
    'sample_cpc': dict(list(univ_cpc.items())[:5])
}

print('__RESULT__:')
print(json.dumps(result))

